   354	    fn test_disable_next_line_should_not_disable_large_span_diagnostics() {
   355	        // This test demonstrates that eslint-disable-next-line should NOT suppress
   356	        // diagnostics for larger constructs (like functions) that contain the disabled line.
   357	        // It should only suppress diagnostics that START on the disabled line.
   358	        let source_text = r"
   359	function test() {
   360	    // eslint-disable-next-line
   361	    console.log('this line is disabled');
   362	    console.warn('this line is not disabled');
   363	}
   364	";
   365	        let allocator = Allocator::default();
   366	        let semantic = process_source(&allocator, source_text);
   367	        let directives =
   368	            DisableDirectivesBuilder::new().build(semantic.source_text(), semantic.comments());
   369	
   370	        // The function spans from line 2 to line 6 (positions 1 to 138)
   371	        let function_span = Span::new(1, 138);
   372	
   373	        // The diagnostic for the entire function should NOT be suppressed
   374	        // even though it contains a disable-next-line directive
   375	        assert!(
   376	            !directives.contains("max-lines-per-function", function_span),
   377	            "eslint-disable-next-line should not suppress diagnostics for the entire function"
   378	        );
   379	
   380	        // A diagnostic that starts on the disabled line (line 4) SHOULD be suppressed
   381	        // The first console.log on line 4 starts at position 59
   382	        let first_console_log_span = Span::new(55, 66);
   383	        assert_eq!(first_console_log_span.source_text(source_text), "console.log");
   384	        assert!(
   385	            directives.contains("no-console", first_console_log_span),
   386	            "eslint-disable-next-line should suppress diagnostics on the next line"
   387	        );
   388	
   389	        // A diagnostic that starts on a non-disabled line (line 5) should NOT be suppressed
   390	        // The second console.log on line 5 starts at position 102
   391	        let second_console_log_span = Span::new(97, 109);
   392	        assert_eq!(second_console_log_span.source_text(source_text), "console.warn");
   393	        assert!(
   394	            !directives.contains("no-console", second_console_log_span),
   395	            "eslint-disable-next-line should NOT suppress diagnostics on lines after the next line"
   396	        );
   397	    }
